import React, { useState, useEffect } from 'react';
import { Box } from '@mui/material';
import FAWDrawer from '../../FAWDrawer';
import FAWInput from '../../FAWInput';
import FAWLoader from '../../FAWLoader';
import { colors } from '../../../../utils/designTokens';

/**
 * Helper function to convert hex color to rgba
 */
const hexToRgba = (hex, alpha = 1) => {
  if (!hex) return null;
  const cleanHex = hex.replace('#', '');
  const r = parseInt(cleanHex.substr(0, 2), 16);
  const g = parseInt(cleanHex.substr(2, 2), 16);
  const b = parseInt(cleanHex.substr(4, 2), 16);
  return `rgba(${r}, ${g}, ${b}, ${alpha})`;
};

const FAWAssignmentMove = ({ 
    open, 
    onClose, 
    assignmentData, 
    onSave
}) => {
    const [sequence, setSequence] = useState('');
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        if (assignmentData && assignmentData.Sequence) {
            setSequence(assignmentData.Sequence.toString());
        }
    }, [assignmentData]);

    const handleSave = async () => {
        const sequenceNumber = parseInt(sequence);
        
        if (!Number.isInteger(sequenceNumber) || sequenceNumber <= 0) {
            setError('Sequence must be a positive integer.');
            return;
        }

        setError('');
        setLoading(true);
        
        try {
            await onSave(sequenceNumber);
            // If successful, the parent will close the drawer
        } catch (error) {
            setError('Error saving sequence. Please try again.');
            setLoading(false);
            // Drawer stays open so user can retry
        }
    };

    const handleCancel = () => {
        setError('');
        setSequence(assignmentData?.Sequence?.toString() || '');
        onClose();
    };

    const handleSequenceChange = (e) => {
        setSequence(e.target.value);
        if (error) {
            setError('');
        }
    };

    return (
        <FAWDrawer
            open={open}
            onClose={handleCancel}
            anchor="right"
            title="Moving"
            actions={[
                {
                    text: 'Cancel',
                    variant: 'outlined',
                    color: 'inherit',
                    onClick: handleCancel,
                    disabled: loading,
                    sx: {
                        minWidth: '80px',
                        borderColor: colors.ui.border.static,
                        color: colors.type.secondary,
                        '&:hover': {
                            borderColor: colors.type.tertiary,
                            backgroundColor: colors.background.secondary
                        }
                    }
                },
                {
                    text: loading ? 'Saving...' : 'Save',
                    variant: 'contained',
                    color: 'primary',
                    onClick: handleSave,
                    loading: loading,
                    disabled: loading,
                    sx: {
                        minWidth: '80px',
                    }
                }
            ]}
            sx={{
                '& .MuiDrawer-paper': {
                    width: '400px',
                    backgroundColor: colors.background.default,
                    border: 'none',
                    boxShadow: '0 8px 32px rgba(0,0,0,0.12)'
                }
            }}
        >
            <Box
                sx={{
                    display: 'flex',
                    flexDirection: 'column',
                    height: '100%'
                }}
            >
                {/* Content */}
                <Box
                    sx={{
                        flex: 1,
                        padding: '24px',
                        display: 'flex',
                        flexDirection: 'column',
                        gap: '16px',
                        position: 'relative'
                    }}
                >
                    {/* Loading Overlay */}
                    {loading && (
                        <Box
                            sx={{
                                position: 'absolute',
                                top: 0,
                                left: 0,
                                right: 0,
                                bottom: 0,
                                backgroundColor: 'rgba(255, 255, 255, 0.8)',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center',
                                zIndex: 1
                            }}
                        >
                            <FAWLoader 
                                type="spinner"
                                size="medium"
                                message="Saving..."
                            />
                        </Box>
                    )}
                    {/* Error Alert */}
                    {error && (
                        <Box
                            sx={{
                                backgroundColor: colors.status.error ? hexToRgba(colors.status.error, 0.08) : '#ffebee',
                                color: colors.status.error,
                                padding: '8px 12px',
                                borderRadius: '4px',
                                fontSize: '14px',
                                border: `1px solid ${colors.status.error ? hexToRgba(colors.status.error, 0.25) : '#ffcdd2'}`
                            }}
                        >
                            {error}
                        </Box>
                    )}

                    {/* Form Field */}
                    <FAWInput
                        type="number"
                        label="Change Sequence"
                        required
                        value={sequence}
                        onChange={handleSequenceChange}
                        placeholder="Enter sequence number"
                        min="1"
                        fullWidth
                        variant="outlined"
                        disabled={loading}
                        sx={{
                            '& .MuiOutlinedInput-input': {
                                padding: '12px 16px',
                                fontSize: '14px'
                            }
                        }}
                    />
                </Box>
            </Box>
        </FAWDrawer>
    );
};

export default FAWAssignmentMove;
